//! NIST ACVP Known-Answer-Test vectors for ML-DSA-44 and ML-DSA-65 — the
//! independent ground truth for the host tests: key generation, deterministic
//! signing, and verification (accept + each tamper-reject reason). All fields
//! are hex.
//!
//! Source: NIST usnistgov/ACVP-Server gen-val ML-DSA-{keyGen,sigGen,sigVer}-
//! FIPS204 internalProjection.json (commit 15c0f3d, RELEASE v1.1.0.40, 2025-06),
//! filtered to signatureInterface="external", preHash="pure", externalMu=false.
//! NIST public-domain notice; separate from RS-Key's AGPL-3.0-only code.

pub(crate) struct KeyGenKat {
    pub set: u16,
    pub seed: &'static str,
    pub pk: &'static str,
}

pub(crate) struct SigGenKat {
    pub set: u16,
    pub rnd: &'static str,
    pub sk: &'static str,
    pub msg: &'static str,
    pub ctx: &'static str,
    pub sig: &'static str,
}

pub(crate) struct SigVerKat {
    pub set: u16,
    pub expected: bool,
    pub reason: &'static str,
    pub pk: &'static str,
    pub msg: &'static str,
    pub ctx: &'static str,
    pub sig: &'static str,
}

